// Bundles the real @carbon/web-components source (from node_modules) into a single
// offline-usable ESM file. The currently published @carbon/web-components 2.x still
// imports old per-size icon paths (16.js/20.js/24.js) but @carbon/icons 11.83+'s "es/"
// build is missing most of them (only ships e.g. 32.js or a generic auto-scaling glyph).
// `npm run icon-overrides` (scripts/build-icon-overrides.mjs) regenerates the exact
// missing files from @carbon/icons/metadata.json, which still has the real per-size data
// — this plugin prefers those regenerated files (correct artwork) and only falls back to
// substituting a same-package differently-sized file (wrong proportions, but still real
// Carbon iconography) for the handful metadata.json doesn't cover either.
import { build } from 'esbuild';
import { existsSync, readdirSync, readFileSync, writeFileSync } from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const iconsPkgRoot = path.dirname(
  fileURLToPath(await import.meta.resolve('@carbon/icons/package.json'))
);
const overridesRoot = path.resolve('scripts/icon-overrides');

// @carbon/web-components' own "es/index.js" barrel doesn't import every component it
// ships — 24 real, documented components (ContainedList, Grid, Copy, the Fluid* family,
// PageHeader, ...) exist as complete source and are listed in custom-elements.json, but
// never get registered as custom elements if you only bundle the package's own index.
// That leaves their markup rendering as plain unstyled text with no interactivity — this
// generates a synthetic entry that imports the real index.js *plus* every component
// folder it silently drops, so nothing in the actual installed source goes unregistered.
const componentsDir = 'node_modules/@carbon/web-components/es/components';
const barrelSrc = readFileSync('node_modules/@carbon/web-components/es/index.js', 'utf8');
const barreled = new Set([...barrelSrc.matchAll(/from ['"]\.\/components\/([^/]+)\//g)].map((m) => m[1]));
const allFolders = readdirSync(componentsDir, { withFileTypes: true }).filter((d) => d.isDirectory()).map((d) => d.name);
const missingFolders = allFolders.filter((f) => !barreled.has(f));
const extraImports = missingFolders.map((f) => {
  const hasIndex = existsSync(path.join(componentsDir, f, 'index.js'));
  const entry = hasIndex ? 'index.js' : `${f}.js`;
  return `import '@carbon/web-components/es/components/${f}/${entry}';`;
});
const syntheticEntryPath = path.resolve('scripts/.wc-full-entry.mjs');
writeFileSync(
  syntheticEntryPath,
  `// Generated by build-wc-bundle.mjs — do not edit; regenerated on every build.\n` +
    `export * from '@carbon/web-components/es/index.js';\n` +
    extraImports.join('\n') + '\n'
);
console.log(`including ${missingFolders.length} component(s) missing from the upstream barrel: ${missingFolders.join(', ')}`);

const iconSizeRedirect = {
  name: 'carbon-icon-size-redirect',
  setup(b) {
    b.onResolve({ filter: /@carbon\/icons\/es\/.+\/(16|20|24|32)\.js$/ }, (args) => {
      const m = args.path.match(/@carbon\/icons\/es\/(.+)\/(16|20|24|32)\.js$/);
      const [, iconName, requestedSize] = m;

      const overridePath = path.join(overridesRoot, iconName, `${requestedSize}.js`);
      if (existsSync(overridePath)) return { path: overridePath };

      const iconDir = path.join(iconsPkgRoot, 'es', iconName);
      if (!existsSync(iconDir)) return null;
      const files = readdirSync(iconDir);
      const preferredOrder = [`${requestedSize}.js`, 'index.js', '32.js', '24.js', '20.js', '16.js'];
      const pick = preferredOrder.find((f) => files.includes(f));
      if (!pick) return null;
      return { path: path.join(iconDir, pick) };
    });
  },
};

await build({
  entryPoints: [syntheticEntryPath],
  bundle: true,
  // IIFE (not 'esm') so this can be loaded with a plain <script src="...">, not
  // <script type="module">. Module scripts are fetched under CORS rules that Chrome/Edge
  // refuse for file:// URLs ("Cross origin requests are only supported for HTTP"), so
  // double-clicking index.html instead of running a server left every custom element
  // undefined and rendering as plain inline text — this is what fixes that.
  format: 'iife',
  outfile: 'assets/carbon-web-components.bundle.js',
  minify: true,
  plugins: [iconSizeRedirect],
  logLevel: 'info',
});

console.log('carbon-web-components bundle written to assets/carbon-web-components.bundle.js');
